// All implementations must embed UnimplementedLightningNodeServer
// for forward compatibility.
type LightningNodeServer interface {
	// Retrieve the latest node info.
	GetNodeInfo(context.Context, *GetNodeInfoRequest) (*GetNodeInfoResponse, error)
	// Retrieve an overview of all known balances.
	GetBalances(context.Context, *GetBalancesRequest) (*GetBalancesResponse, error)
	// Retrieve a new on-chain funding address.
	OnchainReceive(context.Context, *OnchainReceiveRequest) (*OnchainReceiveResponse, error)
	// Send an on-chain payment to the given address.
	OnchainSend(context.Context, *OnchainSendRequest) (*OnchainSendResponse, error)
	// Return a BOLT11 payable invoice.
	Bolt11Receive(context.Context, *Bolt11ReceiveRequest) (*Bolt11ReceiveResponse, error)
	// Return a BOLT11 payable invoice for a given payment hash.
	Bolt11ReceiveForHash(context.Context, *Bolt11ReceiveForHashRequest) (*Bolt11ReceiveForHashResponse, error)
	// Manually claim a payment for a given payment hash.
	Bolt11ClaimForHash(context.Context, *Bolt11ClaimForHashRequest) (*Bolt11ClaimForHashResponse, error)
	// Manually fail a payment for a given payment hash.
	Bolt11FailForHash(context.Context, *Bolt11FailForHashRequest) (*Bolt11FailForHashResponse, error)
	// Return a BOLT11 invoice for receiving via a JIT channel.
	Bolt11ReceiveViaJitChannel(context.Context, *Bolt11ReceiveViaJitChannelRequest) (*Bolt11ReceiveViaJitChannelResponse, error)
	// Return a variable-amount BOLT11 invoice for receiving via a JIT channel.
	Bolt11ReceiveVariableAmountViaJitChannel(context.Context, *Bolt11ReceiveVariableAmountViaJitChannelRequest) (*Bolt11ReceiveVariableAmountViaJitChannelResponse, error)
	// Send a payment for a BOLT11 invoice.
	Bolt11Send(context.Context, *Bolt11SendRequest) (*Bolt11SendResponse, error)
	// Return a BOLT12 offer.
	Bolt12Receive(context.Context, *Bolt12ReceiveRequest) (*Bolt12ReceiveResponse, error)
	// Send a payment for a BOLT12 offer.
	Bolt12Send(context.Context, *Bolt12SendRequest) (*Bolt12SendResponse, error)
	// Send a spontaneous payment (keysend).
	SpontaneousSend(context.Context, *SpontaneousSendRequest) (*SpontaneousSendResponse, error)
	// Create a new outbound channel.
	OpenChannel(context.Context, *OpenChannelRequest) (*OpenChannelResponse, error)
	// Splice funds into a channel.
	SpliceIn(context.Context, *SpliceInRequest) (*SpliceInResponse, error)
	// Splice funds out of a channel.
	SpliceOut(context.Context, *SpliceOutRequest) (*SpliceOutResponse, error)
	// Update the config for a channel.
	UpdateChannelConfig(context.Context, *UpdateChannelConfigRequest) (*UpdateChannelConfigResponse, error)
	// Close a channel cooperatively.
	CloseChannel(context.Context, *CloseChannelRequest) (*CloseChannelResponse, error)
	// Force close a channel.
	ForceCloseChannel(context.Context, *ForceCloseChannelRequest) (*ForceCloseChannelResponse, error)
	// List known channels.
	ListChannels(context.Context, *ListChannelsRequest) (*ListChannelsResponse, error)
	// Get payment details by payment ID.
	GetPaymentDetails(context.Context, *GetPaymentDetailsRequest) (*GetPaymentDetailsResponse, error)
	// List all payments.
	ListPayments(context.Context, *ListPaymentsRequest) (*ListPaymentsResponse, error)
	// List all forwarded payments.
	ListForwardedPayments(context.Context, *ListForwardedPaymentsRequest) (*ListForwardedPaymentsResponse, error)
	// Connect to a peer.
	ConnectPeer(context.Context, *ConnectPeerRequest) (*ConnectPeerResponse, error)
	// Disconnect from a peer.
	DisconnectPeer(context.Context, *DisconnectPeerRequest) (*DisconnectPeerResponse, error)
	// List peers.
	ListPeers(context.Context, *ListPeersRequest) (*ListPeersResponse, error)
	// Sign a message with the node's secret key.
	SignMessage(context.Context, *SignMessageRequest) (*SignMessageResponse, error)
	// Verify a signature against a message and public key.
	VerifySignature(context.Context, *VerifySignatureRequest) (*VerifySignatureResponse, error)
	// Export the pathfinding scores used by the router.
	ExportPathfindingScores(context.Context, *ExportPathfindingScoresRequest) (*ExportPathfindingScoresResponse, error)
	// Send a payment given a BIP 21 URI or BIP 353 Human-Readable Name.
	UnifiedSend(context.Context, *UnifiedSendRequest) (*UnifiedSendResponse, error)
	// Decode a BOLT11 invoice and return its parsed fields.
	DecodeInvoice(context.Context, *DecodeInvoiceRequest) (*DecodeInvoiceResponse, error)
	// Decode a BOLT12 offer and return its parsed fields.
	DecodeOffer(context.Context, *DecodeOfferRequest) (*DecodeOfferResponse, error)
	// List all known short channel IDs in the network graph.
	GraphListChannels(context.Context, *GraphListChannelsRequest) (*GraphListChannelsResponse, error)
	// Get channel info from the network graph by short channel ID.
	GraphGetChannel(context.Context, *GraphGetChannelRequest) (*GraphGetChannelResponse, error)
	// List all known node IDs in the network graph.
	GraphListNodes(context.Context, *GraphListNodesRequest) (*GraphListNodesResponse, error)
	// Get node info from the network graph by node ID.
	GraphGetNode(context.Context, *GraphGetNodeRequest) (*GraphGetNodeResponse, error)
	// Subscribe to a stream of server events.
	SubscribeEvents(*SubscribeEventsRequest, grpc.ServerStreamingServer[events.EventEnvelope]) error
	mustEmbedUnimplementedLightningNodeServer()
}

